mapper.select:
SELECT EXISTS(
    SELECT 1 FROM common_code
    WHERE group_id = #{groupId}
      AND code = #{code}
      AND deleted = 0

      AND id != #{excludeId}

)

mapper.update:
UPDATE common_code
code_name = #{codeName}, code_value = #{codeValue}, sort_order = #{sortOrder}, is_active = #{isActive}, start_at = #{startAt}, end_at = #{endAt}, updated_at = NOW(), updated_by = #{updatedBy}
WHERE id = #{id} AND deleted = 0
